class CompileError {
  CompileError._(this._bc, this._bcOffset);
  factory CompileError(List<int> bytes) {
    final rootRef = fb.BufferContext.fromBytes(bytes);
    return reader.read(rootRef, 0);
  }

  static const fb.Reader<CompileError> reader = _CompileErrorReader();

  final fb.BufferContext _bc;
  final int _bcOffset;

  CompileErrorUnionTypeId? get errorType =>
      CompileErrorUnionTypeId._createOrNull(
        const fb.Uint8Reader().vTableGetNullable(_bc, _bcOffset, 4),
      );
  dynamic get error {
    switch (errorType?.value) {
      case 1:
        return StringLexError.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 2:
        return ParseError.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 3:
        return UnknownBuiltinFunction.reader.vTableGetNullable(
          _bc,
          _bcOffset,
          6,
        );
      case 4:
        return UnknownTypeConstant.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 5:
        return UnknownLoopLabel.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 6:
        return DuplicateVariable.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 7:
        return AssignToConst.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 8:
        return DisabledFeature.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 9:
        return BadSlotName.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 10:
        return InvalidAssignment.reader.vTableGetNullable(_bc, _bcOffset, 6);
      case 11:
        return InvalidTypeLiteralAssignment.reader.vTableGetNullable(
          _bc,
          _bcOffset,
          6,
        );
      case 12:
        return AssignmentToCapturedVariable.reader.vTableGetNullable(
          _bc,
          _bcOffset,
          6,
        );
      default:
        return null;
    }
  }

  @override
